# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Paths, Files}
import java.nio.file.StandardCopyOption
import java.nio.file.Path
import scala.util.{Try, Success, Failure}

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val baseDir = Paths.get("uploads").toAbsolutePath.normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    val filePath = baseDir.resolve(filename).normalize()

    if (!filePath.startsWith(baseDir)) {
      NotFound("File not found")
    } else {
      Try(Source.fromFile(filePath.toFile)) match {
        case Success(source) =>
          val content = source.getLines().mkString("\n")
          source.close()
          Ok(content).as("text/plain")
        case Failure(_) =>
          NotFound("File not found")
      }
    }
  }
}